import{_ as l,o as i,c as e,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const p=JSON.parse('{"title":"RAG 约束","description":"为后续搜索、切片与知识库建设预留的写作与结构约束。","frontmatter":{"title":"RAG 约束","description":"为后续搜索、切片与知识库建设预留的写作与结构约束。"},"headers":[],"relativePath":"standards/rag-guidelines.md","filePath":"standards/rag-guidelines.md","lastUpdated":1777132262000}'),r={name:"standards/rag-guidelines.md"};function o(d,a,n,s,u,c){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="rag-约束" tabindex="-1">RAG 约束 <a class="header-anchor" href="#rag-约束" aria-label="Permalink to &quot;RAG 约束&quot;">​</a></h1><p>如果未来要做知识库、问答系统或更强的站内搜索，文档从一开始就要“可切片”。</p><h2 id="一、不要把所有内容堆成大页" tabindex="-1">一、不要把所有内容堆成大页 <a class="header-anchor" href="#一、不要把所有内容堆成大页" aria-label="Permalink to &quot;一、不要把所有内容堆成大页&quot;">​</a></h2><p>应改为：</p><ul><li>总览页负责导航</li><li>主题页负责解释</li><li>概念页负责精确表达</li><li>笔记页负责个人视角</li></ul><h2 id="二、每页只回答一个主问题" tabindex="-1">二、每页只回答一个主问题 <a class="header-anchor" href="#二、每页只回答一个主问题" aria-label="Permalink to &quot;二、每页只回答一个主问题&quot;">​</a></h2><p>例如：</p><ul><li>“道德经是什么”</li><li>“无为为什么重要”</li><li>“乾卦我目前怎么理解”</li></ul><p>不要把多个问题混成一页。</p><h2 id="三、标题要可检索" tabindex="-1">三、标题要可检索 <a class="header-anchor" href="#三、标题要可检索" aria-label="Permalink to &quot;三、标题要可检索&quot;">​</a></h2><p>优先使用：</p><ul><li>清楚的概念名</li><li>清楚的原典名</li><li>清楚的问题句</li></ul><p>避免只用抽象抒情标题。</p><h2 id="四、段落要可独立理解" tabindex="-1">四、段落要可独立理解 <a class="header-anchor" href="#四、段落要可独立理解" aria-label="Permalink to &quot;四、段落要可独立理解&quot;">​</a></h2><p>每个自然段最好能单独被切出后，仍保留基本含义。</p><p>这意味着：</p><ul><li>少用大量上下文代词</li><li>少用“如前所述”</li><li>少依赖长文中的隐含语境</li></ul><h2 id="五、来源与层级要清楚" tabindex="-1">五、来源与层级要清楚 <a class="header-anchor" href="#五、来源与层级要清楚" aria-label="Permalink to &quot;五、来源与层级要清楚&quot;">​</a></h2><p>最好让系统和读者都能看出：</p><ul><li>这是原典导读</li><li>这是概念整理</li><li>这是作者笔记</li><li>这是后续理论观察</li></ul><h2 id="六、推荐的后续增强字段" tabindex="-1">六、推荐的后续增强字段 <a class="header-anchor" href="#六、推荐的后续增强字段" aria-label="Permalink to &quot;六、推荐的后续增强字段&quot;">​</a></h2><p>如果未来要进一步做知识库，可在 frontmatter 中逐步加入：</p><ul><li><code>category</code></li><li><code>tags</code></li><li><code>source</code></li><li><code>aliases</code></li><li><code>updated</code></li></ul><h2 id="七、关于六十四卦的特别建议" tabindex="-1">七、关于六十四卦的特别建议 <a class="header-anchor" href="#七、关于六十四卦的特别建议" aria-label="Permalink to &quot;七、关于六十四卦的特别建议&quot;">​</a></h2><p>六十四卦不要做成单一总长文。</p><p>更适合：</p><ul><li>一卦一页</li><li>每卦固定模板</li><li>卦与概念、专题双向链接</li></ul><p>这样后续：</p><ul><li>搜索更准</li><li>知识切片更干净</li><li>推荐与引用更稳定</li></ul>',29)])])}const _=l(r,[["render",o]]);export{p as __pageData,_ as default};
